import React, { useState } from 'react';
import { AuthService } from '../services/auth';
import { Loader2, ArrowRight, Mail, KeyRound, CheckCircle2, ChevronLeft } from 'lucide-react';

interface AuthProps {
  onSuccess: (email: string, name: string) => void;
}

type AuthView = 'login' | 'signup' | 'forgot-password';

export default function Auth({ onSuccess }: AuthProps) {
  const [view, setView] = useState<AuthView>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      if (view === 'forgot-password') {
          await AuthService.resetPassword(email);
          setSuccessMsg('If an account exists, a reset link has been sent to your email.');
      } else {
          let res;
          if (view === 'login') {
            res = await AuthService.login(email, password);
          } else {
            res = await AuthService.signup(email, password);
          }
          const name = email.split('@')[0];
          onSuccess(res.email, name);
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogle = async () => {
    setLoading(true);
    try {
      const res = await AuthService.loginWithGoogle();
      const name = "Demo User";
      onSuccess(res.email, name);
    } catch (err) {
      setError('Google Auth failed');
    } finally {
      setLoading(false);
    }
  };

  const switchView = (newView: AuthView) => {
      setView(newView);
      setError('');
      setSuccessMsg('');
  };

  return (
    <div className="min-h-screen bg-[#F8F9FA] dark:bg-dark-bg flex items-center justify-center p-6 relative overflow-hidden isolate transition-colors duration-500">
      {/* Refined Ambient Background with Animation */}
      <div className="absolute inset-0 z-0">
          <div className="absolute top-[-20%] left-[-20%] w-[70vw] h-[70vw] bg-blue-300/30 dark:bg-blue-900/20 rounded-full blur-[100px] mix-blend-multiply dark:mix-blend-screen animate-blob" />
          <div className="absolute bottom-[-20%] right-[-20%] w-[70vw] h-[70vw] bg-indigo-300/30 dark:bg-indigo-900/20 rounded-full blur-[100px] mix-blend-multiply dark:mix-blend-screen animate-blob animation-delay-2000" />
          <div className="absolute top-[40%] left-[50%] translate-x-[-50%] w-[50vw] h-[50vw] bg-purple-200/30 dark:bg-purple-900/20 rounded-full blur-[80px] animate-blob animation-delay-4000 mix-blend-multiply dark:mix-blend-screen" />
          <div className="absolute inset-0 bg-white/40 dark:bg-black/20 backdrop-blur-3xl"></div>
      </div>

      <div className="w-full max-w-[400px] bg-white/70 dark:bg-dark-card/70 backdrop-blur-xl rounded-[2.5rem] shadow-apple border border-white/60 dark:border-white/10 p-8 md:p-10 z-10 animate-scale-in">
        <div className="text-center mb-8">
          <div className="flex justify-center mb-6">
            <div className="relative group">
                <div className="absolute inset-0 bg-navy-900 dark:bg-blue-600 rounded-[1.5rem] blur opacity-20 group-hover:opacity-30 transition-opacity" />
                <div className="relative w-24 h-24 bg-white dark:bg-dark-card rounded-[1.5rem] flex items-center justify-center shadow-apple overflow-hidden transition-transform duration-500 hover:scale-105 border border-white/50 dark:border-white/5">
                    <img 
                      src="/logo.png" 
                      alt="GNG" 
                      className="w-16 h-16 object-contain"
                      onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                    />
                    <span className="hidden text-3xl font-bold text-navy-900 dark:text-white tracking-tighter">GN</span>
                </div>
            </div>
          </div>
          <h1 className="text-2xl font-bold text-navy-900 dark:text-white tracking-tight">Growth Nexis Global</h1>
          <p className="text-slate-500 dark:text-slate-400 text-[15px] font-medium mt-2">
            {view === 'login' && 'Sign in to access myCORE'}
            {view === 'signup' && 'Design your limitless potential'}
            {view === 'forgot-password' && 'Recover your account'}
          </p>
        </div>

        {error && (
            <div className="mb-6 p-3 bg-red-50 dark:bg-red-900/20 text-red-500 dark:text-red-400 text-xs font-semibold rounded-xl text-center border border-red-100 dark:border-red-900/30 animate-fade-in">
                {error}
            </div>
        )}

        {successMsg && (
            <div className="mb-6 p-4 bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400 text-sm font-medium rounded-xl text-center border border-green-100 dark:border-green-900/30 animate-fade-in flex flex-col items-center gap-2">
                <CheckCircle2 size={24} />
                {successMsg}
            </div>
        )}

        {view !== 'forgot-password' || !successMsg ? (
            <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-1 relative">
                <input 
                type="email" 
                required
                value={email}
                onChange={e => setEmail(e.target.value)}
                className="w-full h-12 pl-11 bg-[#F2F2F7]/80 dark:bg-dark-bg/50 hover:bg-[#F2F2F7] dark:hover:bg-dark-bg border-none rounded-xl text-[15px] text-navy-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-navy-900/10 dark:focus:ring-blue-500/30 focus:bg-white dark:focus:bg-dark-bg focus:shadow-sm transition-all outline-none"
                placeholder="Email address"
                />
                <Mail size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
            </div>

            {view !== 'forgot-password' && (
                <div className="space-y-1 relative">
                    <input 
                    type="password" 
                    required
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full h-12 pl-11 bg-[#F2F2F7]/80 dark:bg-dark-bg/50 hover:bg-[#F2F2F7] dark:hover:bg-dark-bg border-none rounded-xl text-[15px] text-navy-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-navy-900/10 dark:focus:ring-blue-500/30 focus:bg-white dark:focus:bg-dark-bg focus:shadow-sm transition-all outline-none"
                    placeholder="Password"
                    />
                    <KeyRound size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                </div>
            )}

            {view === 'login' && (
                <div className="flex justify-end">
                    <button 
                        type="button" 
                        onClick={() => switchView('forgot-password')}
                        className="text-xs font-semibold text-slate-500 hover:text-navy-900 dark:text-slate-400 dark:hover:text-white transition-colors"
                    >
                        Forgot Password?
                    </button>
                </div>
            )}

            <button 
                type="submit"
                disabled={loading}
                className="w-full h-12 bg-navy-900 dark:bg-blue-600 text-white rounded-xl font-semibold shadow-lg shadow-navy-900/20 dark:shadow-blue-600/20 hover:scale-[1.02] active:scale-[0.98] hover:bg-navy-800 dark:hover:bg-blue-500 transition-all flex items-center justify-center gap-2 text-[15px]"
            >
                {loading ? <Loader2 size={20} className="animate-spin" /> : (
                <>
                    {view === 'login' && 'Sign In'}
                    {view === 'signup' && 'Create Account'}
                    {view === 'forgot-password' && 'Send Reset Link'}
                    {view !== 'forgot-password' && <ArrowRight size={16} strokeWidth={2.5} />}
                </>
                )}
            </button>
            </form>
        ) : (
             <button 
                onClick={() => switchView('login')}
                className="w-full h-12 bg-slate-100 dark:bg-dark-bg text-navy-900 dark:text-white rounded-xl font-semibold hover:bg-slate-200 dark:hover:bg-dark-cardHover transition-all flex items-center justify-center gap-2"
             >
                Back to Sign In
             </button>
        )}

        {view !== 'forgot-password' && (
            <>
                <div className="my-8 flex items-center gap-4">
                    <div className="h-px bg-slate-200 dark:bg-slate-700 flex-1" />
                    <span className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Or</span>
                    <div className="h-px bg-slate-200 dark:bg-slate-700 flex-1" />
                </div>

                <button 
                    onClick={handleGoogle}
                    type="button"
                    className="w-full h-12 bg-white/80 dark:bg-dark-bg border border-slate-200/60 dark:border-dark-border text-slate-700 dark:text-slate-300 rounded-xl font-semibold hover:bg-white dark:hover:bg-dark-cardHover active:scale-[0.98] transition-all flex items-center justify-center gap-3 text-[15px] shadow-sm"
                >
                    <svg className="w-5 h-5" viewBox="0 0 24 24">
                        <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                        <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                        <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                        <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                    </svg>
                    Continue with Google
                </button>
            </>
        )}

        {view === 'forgot-password' && !successMsg && (
             <div className="mt-8 text-center">
                <button 
                    onClick={() => switchView('login')}
                    className="text-sm font-semibold text-slate-500 hover:text-navy-900 dark:hover:text-white transition-colors flex items-center justify-center gap-1 mx-auto"
                >
                    <ChevronLeft size={16} /> Back to Sign In
                </button>
             </div>
        )}

        {view !== 'forgot-password' && (
            <p className="text-center mt-8 text-sm text-slate-500 dark:text-slate-400">
            {view === 'login' ? "Don't have an account? " : "Already have an account? "}
            <button 
                onClick={() => switchView(view === 'login' ? 'signup' : 'login')}
                className="text-navy-900 dark:text-white font-bold hover:underline decoration-2 underline-offset-4"
            >
                {view === 'login' ? 'Sign Up' : 'Log In'}
            </button>
            </p>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, createContext, useContext } from 'react';
import { User, Habit, HabitInstance, InterestType, Task, Project } from './types';
import { db } from './services/mockDb';
import { AuthService } from './services/auth';
import { formatDate, getWeekDays } from './utils';
import { NotificationService } from './services/notificationService';

// Icons
import { 
  LayoutDashboard, Compass, BarChart2, Settings, Loader2, CheckSquare, 
  LogOut, Sun, Moon, Search, Bell, Menu, X
} from 'lucide-react';

// Components
import Auth from './components/Auth';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import Interests from './components/Interests';
import Analytics from './components/Analytics';
import SettingsPage from './components/SettingsPage';
import TasksPage from './components/TasksPage';

// --- CONTEXT ---
interface AppContextType {
  user: User | null;
  habits: Habit[];
  currentWeekInstances: Record<string, HabitInstance[]>;
  tasks: Task[];
  projects: Project[];
  refreshData: () => Promise<void>;
  isLoading: boolean;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  completeOnboarding: (interests: InterestType[], finalHabits: Habit[], permissions: any) => Promise<void>;
  handleTrigger: (instanceId: string, value?: number) => Promise<void>;
  updateSettings: (settings: User['settings']) => Promise<void>;
  resetApp: () => Promise<void>;
  isAuthenticated: boolean;
  handleLoginSuccess: (email: string, name: string) => void;
  // Task Helpers
  addTask: (task: Task) => Promise<void>;
  toggleTask: (taskId: string, completed: boolean) => Promise<void>;
  addProject: (project: Project) => Promise<void>;
  deleteTask: (taskId: string) => Promise<void>;
  // Habit Helpers
  toggleHabitFavorite: (habitId: string) => Promise<void>;
  // Theme
  theme: 'light' | 'dark';
  toggleTheme: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

// --- MAIN APP ---

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [habits, setHabits] = useState<Habit[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentWeekInstances, setCurrentWeekInstances] = useState<Record<string, HabitInstance[]>>({});
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [remindersSent, setRemindersSent] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Initialize Theme
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  // Check Auth Status on Mount
  useEffect(() => {
    AuthService.getSession().then(session => {
        if (session && session.user) {
            setIsAuthenticated(true);
            loadUserProfile(session.user.email || '', session.user.user_metadata.name || 'User');
        } else {
            setIsLoading(false);
        }
    });
  }, []);

  const loadUserProfile = async (email: string, name: string) => {
    setIsLoading(true);
    try {
        const u = await db.initUser(email, name);
        setUser(u);
        if (u && u.onboarded) {
            await refreshData();
        }
    } catch (e) {
        console.error("Failed to load user profile", e);
    }
    setIsLoading(false);
  };

  const handleLoginSuccess = async (email: string, name: string) => {
    setIsAuthenticated(true);
    await loadUserProfile(email, name);
  };

  const refreshData = async () => {
    const u = await db.getUser();
    setUser(u);

    if (u && u.onboarded) {
      const h = await db.getHabits();
      setHabits(h);

      const t = await db.getTasks();
      setTasks(t);

      const p = await db.getProjects();
      setProjects(p);

      const weekDates = getWeekDays().map(formatDate);
      const instances = await db.getWeekInstances(weekDates);

      const grouped: Record<string, HabitInstance[]> = {};
      weekDates.forEach(d => grouped[d] = []);
      instances.forEach(i => {
        const date = i.date; 
        if (grouped[date]) grouped[date].push(i);
      });
      setCurrentWeekInstances(grouped);
    }
  };

  // Check for Reminders
  useEffect(() => {
    if (user?.settings.notificationsEnabled && !remindersSent) {
      const checkReminders = () => {
        const today = formatDate(new Date());

        // 1. Habits
        const todaysInstances = currentWeekInstances[today] || [];
        if (todaysInstances.length > 0 && habits.length > 0) {
            NotificationService.sendReminderForHabits(habits, todaysInstances);
        }

        // 2. Tasks
        const dueTasks = tasks.filter(t => !t.completed && t.dueDate === today);
        if (dueTasks.length > 0) {
           NotificationService.send('Task Reminder', `You have ${dueTasks.length} tasks due today: ${dueTasks.map(t => t.title).join(', ')}`);
        }

        setRemindersSent(true);
      };

      // Delay check slightly
      const timer = setTimeout(checkReminders, 3000);
      return () => clearTimeout(timer);
    }
  }, [user, habits, tasks, currentWeekInstances, remindersSent]);

  const completeOnboarding = async (interests: InterestType[], finalHabits: Habit[], permissions: any) => {
    if (!user) return;
    setIsLoading(true);
    await db.completeOnboarding(user.id, interests, finalHabits, permissions);
    await refreshData();
    setIsLoading(false);
  };

  const updateSettings = async (newSettings: User['settings']) => {
    if (user) {
      const updatedUser = { ...user, settings: newSettings };
      setUser(updatedUser);
      await db.updateUserSettings(newSettings);
      if (newSettings.notificationsEnabled) {
        await NotificationService.requestPermission();
      }
    }
  };

  const handleTrigger = async (instanceId: string, value?: number) => {
    const [dateStr] = instanceId.split('_'); 
    let targetDate = dateStr;
    let target = null;

    // Search in current week structure
    for(const d in currentWeekInstances) {
        const found = currentWeekInstances[d].find(i => i.id === instanceId);
        if (found) {
            targetDate = d;
            target = found;
            break;
        }
    }

    if (target) {
        const habit = habits.find(h => h.id === target?.habitId);

        let newState = !target.completed;

        // If Habit has a Goal, calculate completion based on value
        if (habit?.goal && value !== undefined) {
             newState = value >= habit.goal.target;
        }

        const newInstances = { ...currentWeekInstances };
        newInstances[targetDate] = newInstances[targetDate].map(i => 
            i.id === instanceId ? { ...i, completed: newState, value: value !== undefined ? value : i.value } : i
        );
        setCurrentWeekInstances(newInstances);

        if (newState && user?.settings.notificationsEnabled) {
            if (habit && habit.streak >= 3) {
                 if (Math.random() > 0.7) NotificationService.sendStreakCongratulation(habit.name, habit.streak);
            }
            const allDone = newInstances[targetDate].every(i => i.completed);
            if (allDone) {
                NotificationService.sendCompletionCongratulation();
            }
        }
        await db.updateInstanceStatus(instanceId, newState, value);
    }
  };

  const resetApp = async () => {
    await AuthService.logout();
    await db.reset();
    setIsAuthenticated(false);
    setUser(null);
    setHabits([]);
    setTasks([]);
    setProjects([]);
    setCurrentWeekInstances({});
    setActiveTab('dashboard');
  }

  // --- TASK ACTIONS ---
  const addTask = async (task: Task) => {
    await db.addTask(task);
    await refreshData();
  };

  const toggleTask = async (taskId: string, completed: boolean) => {
    await db.updateTask(taskId, { completed });
    await refreshData();
  };

  const addProject = async (project: Project) => {
    await db.addProject(project);
    await refreshData();
  };

  const deleteTask = async (taskId: string) => {
    await db.deleteTask(taskId);
    await refreshData();
  };

  const toggleHabitFavorite = async (habitId: string) => {
    await db.toggleHabitFavorite(habitId);
    await refreshData();
  };


  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-[#F5F5F7] dark:bg-dark-bg text-navy-900 dark:text-white relative overflow-hidden transition-colors duration-500">
        <div className="relative z-10 flex flex-col items-center">
            <Loader2 className="w-10 h-10 animate-spin text-navy-900/50 dark:text-white/50 mb-4" />
            <p className="text-sm font-medium opacity-50">Loading Core...</p>
        </div>
      </div>
    );
  }

  const contextValue = { 
    user, habits, currentWeekInstances, tasks, projects, refreshData, isLoading, 
    activeTab, setActiveTab, completeOnboarding, handleTrigger, 
    updateSettings, resetApp, isAuthenticated, handleLoginSuccess,
    addTask, toggleTask, addProject, deleteTask, toggleHabitFavorite,
    theme, toggleTheme
  };

  return (
    <AppContext.Provider value={contextValue}>
      {!isAuthenticated ? (
        <Auth onSuccess={handleLoginSuccess} />
      ) : !user?.onboarded ? (
        <Onboarding />
      ) : (
        <div className="flex h-screen bg-[#F5F5F7] dark:bg-dark-bg transition-colors duration-500 font-sans text-navy-900 dark:text-dark-text overflow-hidden relative">

          {/* LIQUID GLASS AMBIENT BACKGROUND (Light Mode Only) */}
          <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden dark:opacity-0 transition-opacity duration-1000">
             <div className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-blue-300/30 rounded-full blur-[120px] mix-blend-multiply animate-blob" />
             <div className="absolute top-[-10%] right-[-10%] w-[50vw] h-[50vw] bg-purple-300/30 rounded-full blur-[120px] mix-blend-multiply animate-blob animation-delay-2000" />
             <div className="absolute bottom-[-20%] left-[20%] w-[50vw] h-[50vw] bg-indigo-300/30 rounded-full blur-[120px] mix-blend-multiply animate-blob animation-delay-4000" />
          </div>

          {/* SIDEBAR NAVIGATION (Desktop) */}
          <aside className="hidden md:flex flex-col w-20 lg:w-64 bg-white/60 dark:bg-dark-card backdrop-blur-2xl border-r border-white/50 dark:border-dark-border transition-all duration-300 z-50">
             <div className="h-16 flex items-center justify-center lg:justify-start lg:px-6 border-b border-white/20 dark:border-dark-border/50">
                <div className="relative group flex items-center gap-3">
                  <div className="w-9 h-9 bg-navy-900 dark:bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-xs shadow-glow transition-all">
                    GN
                  </div>
                  <span className="hidden lg:block font-bold text-lg tracking-tight">myCORE</span>
                </div>
             </div>

             <nav className="flex-1 py-6 flex flex-col gap-2 px-3">
                {[
                  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
                  { id: 'tasks', label: 'Tasks', icon: CheckSquare },
                  { id: 'interests', label: 'Interests', icon: Compass },
                  { id: 'analytics', label: 'Analytics', icon: BarChart2 },
                  { id: 'settings', label: 'Settings', icon: Settings },
                ].map(tab => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                      relative group flex items-center gap-3 px-3 py-3 rounded-xl transition-all duration-200
                      ${activeTab === tab.id 
                        ? 'bg-navy-900 text-white dark:bg-blue-600 dark:text-white shadow-lg shadow-navy-900/20 dark:shadow-blue-900/20' 
                        : 'text-slate-600 dark:text-slate-400 hover:bg-white/50 dark:hover:bg-dark-cardHover hover:text-navy-900 dark:hover:text-white'
                      }
                    `}
                  >
                    <tab.icon size={20} strokeWidth={activeTab === tab.id ? 2.5 : 2} className="shrink-0" />
                    <span className="hidden lg:block font-medium text-sm">{tab.label}</span>
                    {activeTab === tab.id && (
                        <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-blue-400 rounded-r-full lg:hidden" />
                    )}
                  </button>
                ))}
             </nav>

             <div className="p-4 border-t border-white/20 dark:border-dark-border">
                <button 
                  onClick={resetApp}
                  className="w-full flex items-center gap-3 px-3 py-3 rounded-xl text-slate-500 hover:bg-red-50 hover:text-red-500 dark:hover:bg-red-900/20 transition-all"
                >
                  <LogOut size={20} />
                  <span className="hidden lg:block font-medium text-sm">Logout</span>
                </button>
             </div>
          </aside>

          {/* MAIN CONTENT AREA */}
          <div className="flex-1 flex flex-col h-full overflow-hidden relative z-10">

             {/* TOP HEADER */}
             <header className="h-16 bg-white/40 dark:bg-dark-card/80 backdrop-blur-xl border-b border-white/30 dark:border-dark-border flex items-center justify-between px-6 z-40 transition-colors duration-300">

                {/* Mobile Menu Trigger */}
                <button 
                  onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                  className="md:hidden p-2 -ml-2 text-navy-900 dark:text-white"
                >
                   {isMobileMenuOpen ? <X /> : <Menu />}
                </button>

                {/* Search Bar */}
                <div className="hidden md:flex items-center gap-3 bg-white/50 dark:bg-dark-bg px-4 py-2 rounded-full w-full max-w-md border border-white/40 dark:border-transparent focus-within:border-blue-500 transition-all shadow-sm">
                   <Search size={16} className="text-slate-500" />
                   <input 
                      placeholder="Enter your search request..." 
                      className="bg-transparent border-none outline-none text-sm w-full placeholder:text-slate-400 text-navy-900 dark:text-white"
                   />
                </div>

                {/* Right Actions */}
                <div className="flex items-center gap-4">
                   <button 
                      onClick={toggleTheme}
                      className="w-10 h-10 rounded-full flex items-center justify-center text-slate-600 hover:bg-white/50 dark:text-slate-400 dark:hover:bg-dark-cardHover transition-all"
                   >
                      {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
                   </button>

                   <button className="w-10 h-10 rounded-full flex items-center justify-center text-slate-600 hover:bg-white/50 dark:text-slate-400 dark:hover:bg-dark-cardHover transition-all relative">
                      <Bell size={20} />
                      <span className="absolute top-2 right-2.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white dark:border-dark-card" />
                   </button>

                   <div className="hidden sm:flex items-center gap-3 pl-4 border-l border-white/30 dark:border-dark-border">
                      <div className="text-right">
                         <div className="text-sm font-bold text-navy-900 dark:text-white leading-none">{user?.name}</div>
                         <div className="text-[10px] font-bold text-slate-500 uppercase tracking-wide mt-1">Pro Plan</div>
                      </div>
                      <div className="w-9 h-9 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xs shadow-md">
                         {user?.name.charAt(0)}
                      </div>
                   </div>
                </div>
             </header>

             {/* SCROLLABLE PAGE CONTENT */}
             <main className="flex-1 overflow-y-auto p-4 md:p-8 scroll-smooth">
                <div className="max-w-7xl mx-auto animate-fade-in">
                  {activeTab === 'dashboard' && <Dashboard />}
                  {activeTab === 'tasks' && <TasksPage />}
                  {activeTab === 'interests' && <Interests />}
                  {activeTab === 'analytics' && <Analytics />}
                  {activeTab === 'settings' && <SettingsPage />}
                </div>
             </main>
          </div>

          {/* MOBILE NAVIGATION DRAWER */}
          {isMobileMenuOpen && (
             <div className="fixed inset-0 z-50 md:hidden">
                <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setIsMobileMenuOpen(false)} />
                <div className="absolute left-0 top-0 bottom-0 w-64 bg-white/90 dark:bg-dark-card backdrop-blur-xl shadow-2xl p-6 animate-slide-right">
                   <div className="flex items-center justify-between mb-8">
                      <div className="font-bold text-xl dark:text-white">myCORE</div>
                      <button onClick={() => setIsMobileMenuOpen(false)}><X className="dark:text-white"/></button>
                   </div>
                   <nav className="flex flex-col gap-2">
                      {[
                        { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
                        { id: 'tasks', label: 'Tasks', icon: CheckSquare },
                        { id: 'interests', label: 'Interests', icon: Compass },
                        { id: 'analytics', label: 'Analytics', icon: BarChart2 },
                        { id: 'settings', label: 'Settings', icon: Settings },
                      ].map(tab => (
                        <button
                          key={tab.id}
                          onClick={() => { setActiveTab(tab.id); setIsMobileMenuOpen(false); }}
                          className={`flex items-center gap-3 p-3 rounded-xl font-medium ${activeTab === tab.id ? 'bg-navy-900 text-white dark:bg-blue-600' : 'text-slate-500 dark:text-slate-400'}`}
                        >
                          <tab.icon size={20} /> {tab.label}
                        </button>
                      ))}
                   </nav>
                   <div className="mt-auto pt-6 border-t dark:border-dark-border">
                      <button onClick={resetApp} className="flex items-center gap-3 text-red-500 font-medium"><LogOut size={20}/> Logout</button>
                   </div>
                </div>
             </div>
          )}
        </div>
      )}
    </AppContext.Provider>
  );
}

import React, { useState } from 'react';
import { useApp } from '../App';
import { getWeekDays, formatDate, getDayName, calculateCompletion } from '../utils';
import { HabitInstance, TriggerType } from '../types';
import * as Icons from 'lucide-react';
import HabitTriggerModal from './HabitTriggerModal';
import AddTaskModal from './AddTaskModal';
import { 
  CheckSquare, ArrowRight, Plus, Calendar, MoreHorizontal, 
  TrendingUp, Activity, Zap, Brain, DollarSign, Smartphone, BookOpen
} from 'lucide-react';

// --- SUB-COMPONENTS ---

const CircularProgress = ({ value, max, size = 120, color = "#10B981", label }: { value: number, max: number, size?: number, color?: string, label?: string }) => {
  const radius = (size - 10) / 2;
  const circumference = radius * 2 * Math.PI;
  const percent = Math.min(100, (value / max) * 100);
  const offset = circumference - (percent / 100) * circumference;

  return (
    <div className="relative flex flex-col items-center justify-center">
      <div className="relative" style={{ width: size, height: size }}>
        {/* Background Circle */}
