      {selectedProject && (
        <ProjectDetailModal 
          project={selectedProject} 
          tasks={tasks} 
          onClose={() => setSelectedProject(null)} 
        />
      )}

      {showAddModal && (
         <AddProjectModal onClose={() => setShowAddModal(false)} />
      )}
    </div>
  );
}

