import { Habit, HabitInstance, InterestType, TriggerType, User, ScheduleType, Task, Project } from '../types';
import { formatDate } from '../utils';

// --- MOCK DATABASE SERVICE ---
// Simulates a backend with LocalStorage persistence

class MockDBService {
  private currentUserCache: User | null = null;

  constructor() {}

  // --- SUGGESTION ENGINE ---
  getSuggestions(interests: InterestType[]): Habit[] {
    const SUGGESTED_HABITS: Habit[] = [
        { id: 'h1', name: 'Morning Run (Gym)', icon: 'Activity', interest: InterestType.HEALTH, schedule: ScheduleType.DAILY, triggerType: TriggerType.LOCATION, triggerConfig: { locationName: 'Gold\'s Gym' }, streak: 0 },
        { id: 'h2', name: 'Market Analysis', icon: 'TrendingUp', interest: InterestType.FINANCE, schedule: ScheduleType.WEEKDAYS, triggerType: TriggerType.APP_OPEN, triggerConfig: { appName: 'Market Terminal', actionDetail: 'Check S&P 500' }, streak: 0 },
        { id: 'h3', name: 'Social Media < 30m', icon: 'Smartphone', interest: InterestType.DETOX, schedule: ScheduleType.DAILY, triggerType: TriggerType.SCREEN_TIME, triggerConfig: { thresholdMinutes: 30 }, streak: 0 },
        { id: 'h4', name: 'Read 1 Chapter', icon: 'BookOpen', interest: InterestType.LEARNING, schedule: ScheduleType.DAILY, triggerType: TriggerType.MANUAL, streak: 0 },
        { id: 'h5', name: 'Deep Work Session', icon: 'Zap', interest: InterestType.PRODUCTIVITY, schedule: ScheduleType.WEEKDAYS, triggerType: TriggerType.APP_OPEN, triggerConfig: { appName: 'Timer Started' }, streak: 0 }
    ];

    let suggestions = SUGGESTED_HABITS.filter(h => interests.includes(h.interest));
    if (suggestions.length < 5) {
        const remaining = 5 - suggestions.length;
        const defaults = SUGGESTED_HABITS.filter(h => !suggestions.find(s => s.id === h.id)).slice(0, remaining);
        suggestions = [...suggestions, ...defaults];
    }
    return suggestions.slice(0, 5);
  }

  // --- USER ---

  async getUser(): Promise<User | null> {
    const json = localStorage.getItem('mycore_user');
    if (json) {
        this.currentUserCache = JSON.parse(json);
        return this.currentUserCache;
    }
    return null;
  }

  async initUser(email: string, name: string): Promise<User> {
    const existing = await this.getUser();
    if (existing) return existing;

    const newUser: User = {
      id: 'u_' + Date.now(),
      email,
      name,
      onboarded: false,
      interests: [],
      settings: { locationEnabled: false, notificationsEnabled: false, screenTimeEnabled: false }
    };

    localStorage.setItem('mycore_user', JSON.stringify(newUser));
    this.currentUserCache = newUser;
    return newUser;
  }

  async completeOnboarding(
    userId: string, 
    interests: InterestType[], 
    habits: Habit[], 
    permissions: { loc: boolean; notif: boolean; screen: boolean }
  ): Promise<void> {
    const user = await this.getUser();
    if (!user) return;

    user.onboarded = true;
    user.interests = interests;
    user.settings = {
        locationEnabled: permissions.loc,
        notificationsEnabled: permissions.notif,
        screenTimeEnabled: permissions.screen
    };

    localStorage.setItem('mycore_user', JSON.stringify(user));
    localStorage.setItem('mycore_habits', JSON.stringify(habits));

    // Seed first week
    await this.seedInstancesForWeek(habits);
  }

  async updateUserSettings(settings: User['settings']): Promise<void> {
    if (this.currentUserCache) {
        this.currentUserCache.settings = settings;
        localStorage.setItem('mycore_user', JSON.stringify(this.currentUserCache));
    }
  }

  // --- HABITS ---

  async getHabits(): Promise<Habit[]> {
    const json = localStorage.getItem('mycore_habits');
    const habits: Habit[] = json ? JSON.parse(json) : [];

    const instances = await this.getAllInstances();

    // Recalculate streaks dynamically
    for (const habit of habits) {
        const habitInstances = instances.filter(i => i.habitId === habit.id);
        this.calculateHabitStrength(habit, habitInstances);
    }

    return habits;
  }

  async toggleHabitFavorite(habitId: string): Promise<void> {
    const json = localStorage.getItem('mycore_habits');
    if (!json) return;
    const habits: Habit[] = JSON.parse(json);
    const idx = habits.findIndex(h => h.id === habitId);
    if (idx !== -1) {
        habits[idx].isFavorite = !habits[idx].isFavorite;
        localStorage.setItem('mycore_habits', JSON.stringify(habits));
    }
  }

  private calculateHabitStrength(habit: Habit, instances: HabitInstance[]): void {
    const sorted = [...instances].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    let currentStreak = 0;
    const todayStr = formatDate(new Date());

    for (const inst of sorted) {
        if (inst.completed) {
            currentStreak++;
        } else {
             // Allow skipping today if not done yet, but break if yesterday was missed
             if (inst.date === todayStr) continue;
             break; 
        }
    }
    habit.streak = currentStreak;
  }

  // --- INSTANCES ---

  private async getAllInstances(): Promise<HabitInstance[]> {
    const json = localStorage.getItem('mycore_instances');
    return json ? JSON.parse(json) : [];
  }

  async getWeekInstances(dates: string[]): Promise<HabitInstance[]> {
    const allInstances = await this.getAllInstances();
    const habits = await this.getHabits();

    let newInstances: HabitInstance[] = [];
    let hasUpdates = false;

    // Check for missing instances and create them (Lazy Load)
    for (const date of dates) {
        const dayHabits = this.getHabitsForDay(date, habits);
        for (const habit of dayHabits) {
             const exists = allInstances.find(i => i.habitId === habit.id && i.date === date);
             if (!exists) {
                 const newInst: HabitInstance = {
                     id: `${date}_${habit.id}`,
                     habitId: habit.id,
                     date: date,
                     completed: false
                 };
                 allInstances.push(newInst);
                 hasUpdates = true;
             }
        }
    }

    if (hasUpdates) {
        localStorage.setItem('mycore_instances', JSON.stringify(allInstances));
    }

    return allInstances.filter(i => dates.includes(i.date));
  }

  async updateInstanceStatus(instanceId: string, completed: boolean, value?: number): Promise<void> {
    const instances = await this.getAllInstances();
    const idx = instances.findIndex(i => i.id === instanceId);
    if (idx !== -1) {
        instances[idx].completed = completed;
        if (completed) instances[idx].completedAt = new Date().toISOString();
        if (value !== undefined) instances[idx].value = value;
        localStorage.setItem('mycore_instances', JSON.stringify(instances));
    }
  }

  // --- TASKS & PROJECTS ---

  async getTasks(): Promise<Task[]> {
    const json = localStorage.getItem('mycore_tasks');
    return json ? JSON.parse(json) : [];
  }

  async addTask(task: Task): Promise<void> {
    const tasks = await this.getTasks();
    tasks.push(task);
    localStorage.setItem('mycore_tasks', JSON.stringify(tasks));
    if (task.projectId) await this.updateProjectProgress(task.projectId);
  }

  async updateTask(taskId: string, updates: Partial<Task>): Promise<void> {
    const tasks = await this.getTasks();
    const idx = tasks.findIndex(t => t.id === taskId);
    if (idx !== -1) {
        tasks[idx] = { ...tasks[idx], ...updates };
        localStorage.setItem('mycore_tasks', JSON.stringify(tasks));
        if (tasks[idx].projectId) await this.updateProjectProgress(tasks[idx].projectId!);
    }
  }

  async deleteTask(taskId: string): Promise<void> {
    let tasks = await this.getTasks();
    const task = tasks.find(t => t.id === taskId);
    tasks = tasks.filter(t => t.id !== taskId);
    localStorage.setItem('mycore_tasks', JSON.stringify(tasks));
    if (task?.projectId) await this.updateProjectProgress(task.projectId);
  }

  async getProjects(): Promise<Project[]> {
    const json = localStorage.getItem('mycore_projects');
    return json ? JSON.parse(json) : [];
  }

  async addProject(project: Project): Promise<void> {
    const projects = await this.getProjects();
    projects.push(project);
    localStorage.setItem('mycore_projects', JSON.stringify(projects));
  }

  async updateProject(projectId: string, updates: Partial<Project>): Promise<void> {
    const projects = await this.getProjects();
    const idx = projects.findIndex(p => p.id === projectId);
    if (idx !== -1) {
        projects[idx] = { ...projects[idx], ...updates };
        // If progress manually updated, update status
        if (updates.progress !== undefined) {
           projects[idx].status = projects[idx].progress === 100 ? 'completed' : 'active';
        }
        localStorage.setItem('mycore_projects', JSON.stringify(projects));
    }
  }

  private async updateProjectProgress(projectId: string): Promise<void> {
    const tasks = await this.getTasks();
    const projectTasks = tasks.filter(t => t.projectId === projectId);
    const total = projectTasks.length;

    // Only auto-update if there are actually tasks. 
    // If a project has 0 tasks, we don't want auto-overwriting manual progress if user set it.
    if (total === 0) return;

    const completed = projectTasks.filter(t => t.completed).length;
    const progress = Math.round((completed / total) * 100);
    const status = progress === 100 ? 'completed' : 'active';

    const projects = await this.getProjects();
    const idx = projects.findIndex(p => p.id === projectId);
    if (idx !== -1) {
        projects[idx].progress = progress;
        projects[idx].status = status;
        localStorage.setItem('mycore_projects', JSON.stringify(projects));
    }
  }

  // --- HELPERS ---

  private getHabitsForDay(dateStr: string, habits: Habit[]): Habit[] {
     const date = new Date(dateStr);
     const dayOfWeek = date.getDay(); // 0 = Sun
     const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;

     return habits.filter(h => {
        if (h.schedule === ScheduleType.DAILY) return true;
        if (h.schedule === ScheduleType.WEEKDAYS) return !isWeekend;
        if (h.schedule === ScheduleType.WEEKENDS) return isWeekend;
        return true;
     });
  }

  private async seedInstancesForWeek(habits: Habit[]) {
     const today = new Date();
     const instances: HabitInstance[] = [];

     // Generate for last 7 days and next 3 days
     for (let i = -7; i <= 3; i++) {
        const d = new Date(today);
        d.setDate(d.getDate() + i);
        const dateStr = formatDate(d);

        const dayHabits = this.getHabitsForDay(dateStr, habits);

        for (const h of dayHabits) {
            instances.push({
                id: `${dateStr}_${h.id}`,
                habitId: h.id,
                date: dateStr,
                completed: false
            });
        }
     }
     localStorage.setItem('mycore_instances', JSON.stringify(instances));
  }

  async reset() {
    localStorage.clear();
    this.currentUserCache = null;
  }
}

export const db = new MockDBService();

import React, { useState, useEffect, createContext, useContext } from 'react';
import { User, Habit, HabitInstance, InterestType, Task, Project } from './types';
import { db } from './services/mockDb';
import { AuthService } from './services/auth';
import { formatDate, getWeekDays } from './utils';
import { NotificationService } from './services/notificationService';

// Icons
import { 
  LayoutDashboard, Compass, BarChart2, Settings, Loader2, CheckSquare, 
  LogOut, Sun, Moon, Search, Bell, Menu, X, Briefcase
} from 'lucide-react';

// Components
import Auth from './components/Auth';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import Interests from './components/Interests';
import Analytics from './components/Analytics';
import SettingsPage from './components/SettingsPage';
import TasksPage from './components/TasksPage';
import ProjectsPage from './components/ProjectsPage';

// --- CONTEXT ---
interface AppContextType {
  user: User | null;
  habits: Habit[];
  currentWeekInstances: Record<string, HabitInstance[]>;
  tasks: Task[];
  projects: Project[];
  refreshData: () => Promise<void>;
  isLoading: boolean;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  completeOnboarding: (interests: InterestType[], finalHabits: Habit[], permissions: any) => Promise<void>;
  handleTrigger: (instanceId: string, value?: number) => Promise<void>;
  updateSettings: (settings: User['settings']) => Promise<void>;
  resetApp: () => Promise<void>;
  isAuthenticated: boolean;
  handleLoginSuccess: (email: string, name: string) => void;
  // Task Helpers
  addTask: (task: Task) => Promise<void>;
  toggleTask: (taskId: string, completed: boolean) => Promise<void>;
  addProject: (project: Project) => Promise<void>;
  updateProject: (projectId: string, updates: Partial<Project>) => Promise<void>;
  deleteTask: (taskId: string) => Promise<void>;
  // Habit Helpers
  toggleHabitFavorite: (habitId: string) => Promise<void>;
  // Theme
  theme: 'light' | 'dark';
  toggleTheme: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

// --- MAIN APP ---

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [habits, setHabits] = useState<Habit[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentWeekInstances, setCurrentWeekInstances] = useState<Record<string, HabitInstance[]>>({});
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [remindersSent, setRemindersSent] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Initialize Theme
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  // Check Auth Status on Mount
  useEffect(() => {
    AuthService.getSession().then(session => {
        if (session && session.user) {
            setIsAuthenticated(true);
            loadUserProfile(session.user.email || '', session.user.user_metadata.name || 'User');
        } else {
            setIsLoading(false);
        }
    });
  }, []);

  const loadUserProfile = async (email: string, name: string) => {
    setIsLoading(true);
    try {
        const u = await db.initUser(email, name);
        setUser(u);
        if (u && u.onboarded) {
            await refreshData();
        }
    } catch (e) {
        console.error("Failed to load user profile", e);
    }
    setIsLoading(false);
  };

  const handleLoginSuccess = async (email: string, name: string) => {
    setIsAuthenticated(true);
    await loadUserProfile(email, name);
  };

  const refreshData = async () => {
    const u = await db.getUser();
    setUser(u);

    if (u && u.onboarded) {
      const h = await db.getHabits();
      setHabits(h);

      const t = await db.getTasks();
      setTasks(t);

      const p = await db.getProjects();
      setProjects(p);

      const weekDates = getWeekDays().map(formatDate);
      const instances = await db.getWeekInstances(weekDates);

      const grouped: Record<string, HabitInstance[]> = {};
      weekDates.forEach(d => grouped[d] = []);
      instances.forEach(i => {
        const date = i.date; 
        if (grouped[date]) grouped[date].push(i);
      });
      setCurrentWeekInstances(grouped);
    }
  };

  // Check for Reminders
  useEffect(() => {
    if (user?.settings.notificationsEnabled && !remindersSent) {
      const checkReminders = () => {
        const today = formatDate(new Date());

        // 1. Habits
        const todaysInstances = currentWeekInstances[today] || [];
        if (todaysInstances.length > 0 && habits.length > 0) {
            NotificationService.sendReminderForHabits(habits, todaysInstances);
        }

        // 2. Tasks
        const dueTasks = tasks.filter(t => !t.completed && t.dueDate === today);
        if (dueTasks.length > 0) {
           NotificationService.send('Task Reminder', `You have ${dueTasks.length} tasks due today: ${dueTasks.map(t => t.title).join(', ')}`);
        }

        setRemindersSent(true);
      };

      // Delay check slightly
      const timer = setTimeout(checkReminders, 3000);
      return () => clearTimeout(timer);
    }
  }, [user, habits, tasks, currentWeekInstances, remindersSent]);

  const completeOnboarding = async (interests: InterestType[], finalHabits: Habit[], permissions: any) => {
    if (!user) return;
    setIsLoading(true);
    await db.completeOnboarding(user.id, interests, finalHabits, permissions);
    await refreshData();
    setIsLoading(false);
  };

  const updateSettings = async (newSettings: User['settings']) => {
    if (user) {
      const updatedUser = { ...user, settings: newSettings };
      setUser(updatedUser);
      await db.updateUserSettings(newSettings);
      if (newSettings.notificationsEnabled) {
        await NotificationService.requestPermission();
      }
    }
  };

  const handleTrigger = async (instanceId: string, value?: number) => {
    const [dateStr] = instanceId.split('_'); 
    let targetDate = dateStr;
    let target = null;

    // Search in current week structure
    for(const d in currentWeekInstances) {
        const found = currentWeekInstances[d].find(i => i.id === instanceId);
        if (found) {
            targetDate = d;
            target = found;
            break;
        }
    }

    if (target) {
        const habit = habits.find(h => h.id === target?.habitId);

        let newState = !target.completed;

        // If Habit has a Goal, calculate completion based on value
        if (habit?.goal && value !== undefined) {
             newState = value >= habit.goal.target;
        }

        const newInstances = { ...currentWeekInstances };
        newInstances[targetDate] = newInstances[targetDate].map(i => 
            i.id === instanceId ? { ...i, completed: newState, value: value !== undefined ? value : i.value } : i
        );
        setCurrentWeekInstances(newInstances);

        if (newState && user?.settings.notificationsEnabled) {
            if (habit && habit.streak >= 3) {
                 if (Math.random() > 0.7) NotificationService.sendStreakCongratulation(habit.name, habit.streak);
            }
            const allDone = newInstances[targetDate].every(i => i.completed);
            if (allDone) {
                NotificationService.sendCompletionCongratulation();
            }
        }
        await db.updateInstanceStatus(instanceId, newState, value);
    }
  };

  const resetApp = async () => {
    await AuthService.logout();
    await db.reset();
    setIsAuthenticated(false);
    setUser(null);
    setHabits([]);
    setTasks([]);
    setProjects([]);
    setCurrentWeekInstances({});
    setActiveTab('dashboard');
  }

  // --- TASK ACTIONS ---
  const addTask = async (task: Task) => {
    await db.addTask(task);
    await refreshData();
  };

  const toggleTask = async (taskId: string, completed: boolean) => {
    await db.updateTask(taskId, { completed });
    await refreshData();
  };

  const addProject = async (project: Project) => {
    await db.addProject(project);
    await refreshData();
  };

  const updateProject = async (projectId: string, updates: Partial<Project>) => {
    await db.updateProject(projectId, updates);
    await refreshData();
  };

  const deleteTask = async (taskId: string) => {
    await db.deleteTask(taskId);
    await refreshData();
  };

  const toggleHabitFavorite = async (habitId: string) => {
    await db.toggleHabitFavorite(habitId);
    await refreshData();
  };


  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-[#F5F5F7] dark:bg-dark-bg text-navy-900 dark:text-white relative overflow-hidden transition-colors duration-500">
        <div className="relative z-10 flex flex-col items-center">
            <Loader2 className="w-10 h-10 animate-spin text-navy-900/50 dark:text-white/50 mb-4" />
            <p className="text-sm font-medium opacity-50">Loading Core...</p>
        </div>
      </div>
    );
  }

  const contextValue = { 
    user, habits, currentWeekInstances, tasks, projects, refreshData, isLoading, 
    activeTab, setActiveTab, completeOnboarding, handleTrigger, 
    updateSettings, resetApp, isAuthenticated, handleLoginSuccess,
    addTask, toggleTask, addProject, updateProject, deleteTask, toggleHabitFavorite,
    theme, toggleTheme
  };

  return (
    <AppContext.Provider value={contextValue}>
      {!isAuthenticated ? (
        <Auth onSuccess={handleLoginSuccess} />
      ) : !user?.onboarded ? (
        <Onboarding />
      ) : (
        <div className="flex h-screen bg-[#F5F5F7] dark:bg-dark-bg transition-colors duration-500 font-sans text-navy-900 dark:text-dark-text overflow-hidden relative">

          {/* LIQUID GLASS AMBIENT BACKGROUND (Light Mode Only) */}
          <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden dark:opacity-0 transition-opacity duration-1000">
             <div className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-blue-300/30 rounded-full blur-[120px] mix-blend-multiply animate-blob" />
             <div className="absolute top-[-10%] right-[-10%] w-[50vw] h-[50vw] bg-purple-300/30 rounded-full blur-[120px] mix-blend-multiply animate-blob animation-delay-2000" />
             <div className="absolute bottom-[-20%] left-[20%] w-[50vw] h-[50vw] bg-indigo-300/30 rounded-full blur-[120px] mix-blend-multiply animate-blob animation-delay-4000" />
          </div>

          {/* SIDEBAR NAVIGATION (Desktop) */}
          <aside className="hidden md:flex flex-col w-20 lg:w-64 bg-white/60 dark:bg-dark-card backdrop-blur-2xl border-r border-white/50 dark:border-dark-border transition-all duration-300 z-50">
             <div className="h-16 flex items-center justify-center lg:justify-start lg:px-6 border-b border-white/20 dark:border-dark-border/50">
                <div className="relative group flex items-center gap-3">
                  <div className="w-9 h-9 bg-navy-900 dark:bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-xs shadow-glow transition-all">
                    GN
                  </div>
                  <span className="hidden lg:block font-bold text-lg tracking-tight">myCORE</span>
                </div>
             </div>

             <nav className="flex-1 py-6 flex flex-col gap-2 px-3">
                {[
                  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
                  { id: 'projects', label: 'Projects', icon: Briefcase },
                  { id: 'tasks', label: 'Tasks', icon: CheckSquare },
                  { id: 'interests', label: 'Interests', icon: Compass },
                  { id: 'analytics', label: 'Analytics', icon: BarChart2 },
                  { id: 'settings', label: 'Settings', icon: Settings },
                ].map(tab => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                      relative group flex items-center gap-3 px-3 py-3 rounded-xl transition-all duration-200
                      ${activeTab === tab.id 
                        ? 'bg-navy-900 text-white dark:bg-blue-600 dark:text-white shadow-lg shadow-navy-900/20 dark:shadow-blue-900/20' 
                        : 'text-slate-600 dark:text-slate-400 hover:bg-white/50 dark:hover:bg-dark-cardHover hover:text-navy-900 dark:hover:text-white'
                      }
                    `}
                  >
                    <tab.icon size={20} strokeWidth={activeTab === tab.id ? 2.5 : 2} className="shrink-0" />
                    <span className="hidden lg:block font-medium text-sm">{tab.label}</span>
                    {activeTab === tab.id && (
                        <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-blue-400 rounded-r-full lg:hidden" />
                    )}
