import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../App';
import { Task, Project, Priority } from '../types';
import { formatDate } from '../utils';
import { 
  Plus, Calendar as CalendarIcon, List, Clock, Briefcase, 
  Flag, ChevronLeft, ChevronRight, CheckCircle2, Trash2, CheckSquare, Bell,
  Filter, X, Tag, Layers, RotateCcw
} from 'lucide-react';
import AddTaskModal from './AddTaskModal';

// --- SUB-COMPONENTS ---

const TaskItem: React.FC<{ 
  task: Task; 
  onToggle: () => void; 
  onDelete: () => void; 
  projectName?: string 
}> = ({ task, onToggle, onDelete, projectName }) => {
  const [isToggling, setIsToggling] = useState(false);

  const handleToggle = () => {
    setIsToggling(true);
    onToggle();
    setTimeout(() => setIsToggling(false), 400);
  };

  return (
    <div className={`
      group flex items-start gap-4 p-4 transition-all duration-300 border-b border-slate-100 dark:border-dark-border/50 last:border-0 
      hover:bg-slate-50/80 dark:hover:bg-dark-cardHover/50 
      ${task.completed ? 'opacity-60 bg-slate-50/30 dark:bg-transparent' : ''}
    `}>
      <button 
        onClick={handleToggle}
        className={`
          mt-0.5 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300
          ${isToggling ? 'scale-125' : 'scale-100'}
          ${task.completed 
            ? 'bg-navy-900 border-navy-900 dark:bg-blue-600 dark:border-blue-600 text-white shadow-glow' 
            : 'border-slate-300 dark:border-slate-600 hover:border-navy-900 dark:hover:border-blue-500'
          }
        `}
      >
        {task.completed && (
          <CheckCircle2 
            size={14} 
            strokeWidth={3} 
            className="animate-scale-in" 
          />
        )}
      </button>

      <div className="flex-1 min-w-0">
        <h4 className={`
          text-[15px] font-medium leading-snug transition-all duration-500
          ${task.completed ? 'line-through text-slate-400 italic' : 'text-slate-900 dark:text-slate-200'}
        `}>
          {task.title}
        </h4>
        <div className="flex flex-wrap items-center gap-2 mt-1.5">
           {projectName && (
             <span className="text-[10px] bg-slate-100 dark:bg-dark-bg text-slate-600 dark:text-slate-400 font-bold px-2 py-0.5 rounded-md uppercase tracking-wider border border-slate-200/50 dark:border-dark-border">
               {projectName}
             </span>
           )}
           {task.priority !== Priority.MEDIUM && (
             <span className={`text-[10px] font-bold flex items-center gap-1 ${task.priority === Priority.HIGH ? 'text-red-500' : 'text-blue-500'}`}>
                <Flag size={10} fill="currentColor" /> {task.priority}
             </span>
           )}
           <span className={`text-[11px] font-medium flex items-center gap-1 ${new Date(task.dueDate) < new Date() && !task.completed ? 'text-red-500' : 'text-slate-400'}`}>
              <Clock size={10} /> {task.dueDate}
           </span>
        </div>
      </div>

      <button 
        onClick={onDelete} 
        className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all duration-200 p-2 hover:bg-red-50 dark:hover:bg-red-900/10 rounded-full"
      >
         <Trash2 size={16} />
      </button>
    </div>
  );
};

const CalendarView = ({ tasks, onDateSelect, selectedDate }: { tasks: Task[], onDateSelect: (d: string) => void, selectedDate: string }) => {
  const [currentDate, setCurrentDate] = useState(new Date());

  const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const getFirstDay = (year: number, month: number) => new Date(year, month, 1).getDay();

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const startDay = getFirstDay(year, month);
  const offset = startDay === 0 ? 6 : startDay - 1;

  const days = [];
  for(let i=0; i<offset; i++) days.push(null);
  for(let i=1; i<=daysInMonth; i++) days.push(new Date(year, month, i));

  const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  return (
    <div className="bg-white/60 dark:bg-dark-card backdrop-blur-xl p-6 rounded-[2.5rem] shadow-apple border border-white/50 dark:border-dark-border">
      <div className="flex items-center justify-between mb-6">
        <h3 className="font-bold text-lg text-navy-900 dark:text-white tracking-tight ml-2">{monthName}</h3>
        <div className="flex gap-1">
            <button onClick={() => setCurrentDate(new Date(year, month - 1, 1))} className="p-2 hover:bg-white/50 dark:hover:bg-dark-bg rounded-full text-slate-500"><ChevronLeft size={20}/></button>
            <button onClick={() => setCurrentDate(new Date(year, month + 1, 1))} className="p-2 hover:bg-white/50 dark:hover:bg-dark-bg rounded-full text-slate-500"><ChevronRight size={20}/></button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-2 text-center mb-4">
         {['M','T','W','T','F','S','S'].map((d,i) => <span key={i} className="text-xs font-bold text-slate-400 dark:text-slate-600 uppercase tracking-widest">{d}</span>)}
      </div>

      <div className="grid grid-cols-7 gap-2">
         {days.map((day, idx) => {
            if(!day) return <div key={idx} />;
            const dateStr = formatDate(day);
            const isSelected = dateStr === selectedDate;
            const isToday = formatDate(new Date()) === dateStr;
            const dayTasks = tasks.filter(t => t.dueDate === dateStr && !t.completed);
            const hasTask = dayTasks.length > 0;

            return (
              <button 
                key={idx}
                onClick={() => onDateSelect(dateStr)}
                className={`
                  relative h-10 w-10 mx-auto rounded-full flex items-center justify-center text-sm font-medium transition-all duration-300
                  ${isSelected 
                    ? 'bg-navy-900 text-white shadow-lg scale-110 dark:bg-blue-600' 
                    : isToday 
                        ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20 font-bold' 
                        : 'text-slate-600 dark:text-slate-400 hover:bg-white/50 dark:hover:bg-dark-bg'
                  }
                `}
              >
                {day.getDate()}
                {hasTask && !isSelected && (
                   <div className="absolute bottom-1 w-1 h-1 rounded-full bg-blue-400" />
                )}
              </button>
            )
         })}
      </div>
    </div>
  );
};

// --- MAIN COMPONENT ---

export default function TasksPage() {
  const { tasks, projects, toggleTask, deleteTask } = useApp();
  const [view, setView] = useState<'list' | 'calendar'>('list');
  const [selectedDate, setSelectedDate] = useState(formatDate(new Date()));
  const [showTaskModal, setShowTaskModal] = useState(false);

  // Undo System State
  const [lastDeletedTask, setLastDeletedTask] = useState<Task | null>(null);
  const [isUndoVisible, setIsUndoVisible] = useState(false);
  const undoTimerRef = useRef<NodeJS.Timeout | null>(null);

  // Filter State
  const [showFilters, setShowFilters] = useState(false);
  const [filterProject, setFilterProject] = useState<string>('all');
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [filterPriority, setFilterPriority] = useState<string>('all');

  // Derive Data
  const categories = Array.from(new Set(tasks.map(t => t.category).filter(Boolean))).sort();

  // Handle deletion with undo
  const initiateDelete = (task: Task) => {
    // If there's already a task waiting to be deleted, finalize it
    if (lastDeletedTask) {
        finalizeDelete();
    }

    setLastDeletedTask(task);
    setIsUndoVisible(true);

    // Set a timer to finalize the deletion after 5 seconds
    if (undoTimerRef.current) clearTimeout(undoTimerRef.current);
    undoTimerRef.current = setTimeout(() => {
        finalizeDelete();
    }, 5000);
  };

  const finalizeDelete = () => {
    if (lastDeletedTask) {
        deleteTask(lastDeletedTask.id);
        setLastDeletedTask(null);
        setIsUndoVisible(false);
    }
    if (undoTimerRef.current) clearTimeout(undoTimerRef.current);
  };

  const handleUndo = () => {
    if (undoTimerRef.current) clearTimeout(undoTimerRef.current);
    setLastDeletedTask(null);
    setIsUndoVisible(false);
  };

  // 1. Apply Global Filters (Proj, Cat, Prio) + Exclude pending deletion
  const globalFilteredTasks = tasks.filter(task => {
      // Don't show if currently "deleted" in the undo state
      if (lastDeletedTask && task.id === lastDeletedTask.id) return false;

      // Project Filter
      if (filterProject !== 'all') {
          if (filterProject === 'unassigned') {
              if (task.projectId) return false;
          } else if (task.projectId !== filterProject) {
              return false;
          }
      }
      // Category Filter
      if (filterCategory !== 'all' && task.category !== filterCategory) return false;
      // Priority Filter
      if (filterPriority !== 'all' && task.priority !== filterPriority) return false;

      return true;
  });

  // 2. Apply View Specific Logic (Date sorting or filtering)
  const displayTasks = view === 'list' 
    ? [...globalFilteredTasks].sort((a,b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime())
    : globalFilteredTasks.filter(t => t.dueDate === selectedDate);

  const activeFiltersCount = (filterProject !== 'all' ? 1 : 0) + (filterCategory !== 'all' ? 1 : 0) + (filterPriority !== 'all' ? 1 : 0);

  const clearFilters = () => {
      setFilterProject('all');
      setFilterCategory('all');
      setFilterPriority('all');
  };

  return (
    <div className="space-y-8 pb-20 relative min-h-[80vh]">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-bold text-navy-900 dark:text-white tracking-tight">Daily Execution</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">Consistency is the bridge between goals and accomplishment.</p>
        </div>
        <div className="flex bg-white/40 dark:bg-dark-card/50 backdrop-blur-sm p-1 rounded-2xl shadow-sm border border-white/50 dark:border-dark-border transition-all w-fit self-end md:self-auto">
           <button onClick={() => setView('list')} className={`p-2.5 rounded-xl transition-all ${view === 'list' ? 'bg-white dark:bg-dark-card text-navy-900 dark:text-white shadow-sm' : 'text-slate-400'}`}>
              <List size={20} />
           </button>
           <button onClick={() => setView('calendar')} className={`p-2.5 rounded-xl transition-all ${view === 'calendar' ? 'bg-white dark:bg-dark-card text-navy-900 dark:text-white shadow-sm' : 'text-slate-400'}`}>
              <CalendarIcon size={20} />
           </button>
        </div>
      </div>

      {/* TASKS & CALENDAR GRID */}
      <div className={`grid grid-cols-1 ${view === 'calendar' ? 'lg:grid-cols-2' : ''} gap-8`}>

         {view === 'calendar' && (
            <div className="animate-fade-in-up">
              <CalendarView 
                tasks={globalFilteredTasks} 
                onDateSelect={setSelectedDate} 
                selectedDate={selectedDate} 
              />
            </div>
         )}

         <div className="bg-white/60 dark:bg-dark-card backdrop-blur-xl rounded-[2.5rem] p-8 shadow-apple border border-white/50 dark:border-dark-border min-h-[500px] relative animate-fade-in-up flex flex-col">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h3 className="text-2xl font-bold text-navy-900 dark:text-white tracking-tight">
                    {view === 'calendar' ? `${new Date(selectedDate).toLocaleDateString(undefined, {weekday: 'long'})}` : 'Task Feed'}
                </h3>
                <p className="text-slate-500 font-medium text-sm mt-1">{displayTasks.filter(t => !t.completed).length} pending items</p>
              </div>

              <div className="flex gap-2">
                 <button 
                    onClick={() => setShowFilters(!showFilters)} 
                    className={`relative w-12 h-12 rounded-full flex items-center justify-center transition-all ${showFilters || activeFiltersCount > 0 ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-600' : 'bg-slate-50 dark:bg-dark-bg text-slate-400 hover:bg-slate-100 dark:hover:bg-dark-cardHover'}`}
                 >
                    <Filter size={20} />
                    {activeFiltersCount > 0 && !showFilters && (
