        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] animate-fade-in-up">
            <div className="bg-navy-900/80 dark:bg-dark-card/90 backdrop-blur-2xl px-6 py-4 rounded-[1.5rem] shadow-2xl border border-white/20 dark:border-dark-border flex items-center gap-6 min-w-[320px]">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/10 rounded-full flex items-center justify-center text-white">
                        <Trash2 size={18} />
                    </div>
                    <div>
                        <p className="text-white text-sm font-bold truncate max-w-[150px]">Task Removed</p>
                        <p className="text-white/50 text-[10px] font-bold uppercase tracking-widest">Finalizing in 5s...</p>
                    </div>
                </div>
                <button 
                    onClick={handleUndo}
                    className="ml-auto flex items-center gap-2 bg-white text-navy-900 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider hover:bg-slate-100 transition-all active:scale-95 shadow-lg"
                >
                    <RotateCcw size={14} /> Undo
                </button>
            </div>
        </div>
      )}

      {showTaskModal && <AddTaskModal onClose={() => setShowTaskModal(false)} />}
    </div>
  );
}

export const InterestType = {
  HEALTH: 'Health',
  PRODUCTIVITY: 'Productivity',
  FINANCE: 'Finance',
  LEARNING: 'Learning',
  DETOX: 'Detox',
  CUSTOM: 'Custom',
} as const;

export type InterestType = typeof InterestType[keyof typeof InterestType] | string;

export enum TriggerType {
  MANUAL = 'MANUAL',
  LOCATION = 'LOCATION', // Geofence
  APP_OPEN = 'APP_OPEN', // Interaction
  SCREEN_TIME = 'SCREEN_TIME', // Input validation
}

export enum ScheduleType {
  DAILY = 'Daily',
  WEEKDAYS = 'Weekdays',
  WEEKENDS = 'Weekends',
  CUSTOM = 'Custom',
}

export interface Habit {
  id: string;
  name: string;
  icon: string; // Lucide icon name or simple string identifier
  interest: InterestType;
  schedule: ScheduleType;
  triggerType: TriggerType;
  triggerConfig?: {
    locationName?: string;
    thresholdMinutes?: number;
    appName?: string;
    actionDetail?: string; // Specific action description (e.g., "Check S&P 500")
  };
  // New Goal Configuration
  goal?: {
    target: number;
    unit: string; // e.g. 'km', 'pages', 'min'
  };
  streak: number;
  isFavorite?: boolean;
}

export interface HabitInstance {
  id: string;
  habitId: string;
  date: string; // YYYY-MM-DD
  completed: boolean;
  completedAt?: string;
  value?: number; // Current progress value (e.g. 5)
}

export interface User {
  id: string;
  email: string;
  name: string;
  onboarded: boolean;
  interests: InterestType[];
  settings: {
    locationEnabled: boolean;
    notificationsEnabled: boolean;
    screenTimeEnabled: boolean;
  };
}

export interface DayStats {
  date: string; // YYYY-MM-DD
  dayName: string; // Mon, Tue...
  completionRate: number; // 0-100
  totalHabits: number;
  completedHabits: number;
}

// --- TASKS & PROJECTS ---

export enum Priority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
}

export enum ReminderType {
  AT_DEADLINE = 'At Deadline',
  ONE_HOUR_BEFORE = '1 Hour Before',
  ONE_DAY_BEFORE = '1 Day Before',
  CUSTOM = 'Custom',
}

export interface Task {
  id: string;
  title: string;
  description?: string;
  dueDate: string; // YYYY-MM-DD
  dueTime?: string; // HH:MM
  priority: Priority;
  category: string; // e.g. Work, Personal
  projectId?: string;
  completed: boolean;
  reminder?: {
    type: ReminderType;
    customDate?: string; // ISO
  };
  subtasks?: { id: string; title: string; completed: boolean }[];
