  const [filter, setFilter] = useState<'all' | 'active' | 'completed' | 'archived'>('all');
  const [search, setSearch] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);

  const filteredProjects = projects.filter(p => {
    const matchesFilter = filter === 'all' || p.status === filter;
    const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const activeDetailProject = selectedProject ? projects.find(p => p.id === selectedProject.id) || selectedProject : null;

  const activeCount = projects.filter(p => p.status === 'active').length;
  const avgProgress = projects.length > 0 ? Math.round(projects.reduce((acc, p) => acc + p.progress, 0) / projects.length) : 0;
  const completedCount = projects.filter(p => p.status === 'completed').length;

  return (
    <div className="space-y-8 animate-fade-in pb-12">

      {/* 1. Header & Stats Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-bold text-navy-900 dark:text-white tracking-tight">Project Hub</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">Design and track high-level roadmap initiatives.</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-navy-900 dark:bg-blue-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-navy-900/20 dark:shadow-blue-900/20 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center gap-2"
        >
          <Plus size={20} /> New Project
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
         <div className="bg-white/60 dark:bg-dark-card backdrop-blur-xl p-6 rounded-[2rem] border border-white/40 dark:border-dark-border shadow-glass dark:shadow-dark-soft flex items-center gap-6">
            <div className="w-14 h-14 bg-blue-50 dark:bg-blue-500/10 rounded-2xl flex items-center justify-center text-blue-600 dark:text-blue-400">
               <Activity size={24} />
            </div>
            <div>
               <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Active Initiatives</div>
               <div className="text-2xl font-bold text-navy-900 dark:text-white">{activeCount}</div>
            </div>
         </div>
         <div className="bg-white/60 dark:bg-dark-card backdrop-blur-xl p-6 rounded-[2rem] border border-white/40 dark:border-dark-border shadow-glass dark:shadow-dark-soft flex items-center gap-6">
            <div className="w-14 h-14 bg-green-50 dark:bg-green-500/10 rounded-2xl flex items-center justify-center text-green-600 dark:text-green-400">
               <TrendingUp size={24} />
            </div>
            <div>
               <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Global Progress</div>
               <div className="text-2xl font-bold text-navy-900 dark:text-white">{avgProgress}%</div>
            </div>
         </div>
         <div className="bg-white/60 dark:bg-dark-card backdrop-blur-xl p-6 rounded-[2rem] border border-white/40 dark:border-dark-border shadow-glass dark:shadow-dark-soft flex items-center gap-6">
            <div className="w-14 h-14 bg-purple-50 dark:bg-purple-500/10 rounded-2xl flex items-center justify-center text-purple-600 dark:text-purple-400">
               <BarChart3 size={24} />
            </div>
            <div>
               <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Units</div>
               <div className="text-2xl font-bold text-navy-900 dark:text-white">{projects.length}</div>
            </div>
         </div>
      </div>

      {/* 2. Search & Filters */}
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
         <div className="flex bg-white/40 dark:bg-dark-card/50 backdrop-blur-sm p-1.5 rounded-2xl border border-white/50 dark:border-dark-border shadow-sm w-full md:w-auto overflow-x-auto no-scrollbar">
            {['all', 'active', 'completed', 'archived'].map(f => (
               <button
                  key={f}
                  onClick={() => setFilter(f as any)}
                  className={`px-6 py-2 rounded-xl text-xs font-bold uppercase tracking-wider transition-all whitespace-nowrap ${
                     filter === f 
                        ? 'bg-white dark:bg-dark-card text-navy-900 dark:text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'
                  }`}
               >
                  {f}
               </button>
            ))}
         </div>

         <div className="relative w-full md:w-72">
            <input 
               type="text" 
               placeholder="Search projects..."
               value={search}
               onChange={(e) => setSearch(e.target.value)}
               className="w-full h-12 pl-12 pr-4 bg-white/40 dark:bg-dark-card/50 backdrop-blur-sm border border-white/50 dark:border-dark-border rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all placeholder:text-slate-400"
            />
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
         </div>
      </div>

      {/* 3. Project Grid */}
      {filteredProjects.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredProjects.map(project => (
            <ProjectGridCard 
                key={project.id} 
                project={project} 
                tasks={tasks}
                onClick={() => setSelectedProject(project)}
            />
          ))}
        </div>
      ) : (
        <div className="bg-white/40 dark:bg-dark-card/30 backdrop-blur-md rounded-[3rem] p-20 border-2 border-dashed border-white/50 dark:border-dark-border flex flex-col items-center justify-center text-center">
            <div className="w-20 h-20 bg-slate-50 dark:bg-dark-bg rounded-full flex items-center justify-center text-slate-300 dark:text-slate-700 mb-6">
               <Briefcase size={40} />
            </div>
            <h3 className="text-xl font-bold text-navy-900 dark:text-white mb-2">No projects found</h3>
            <p className="text-slate-500 max-w-xs leading-relaxed">Adjust your filters or start fresh with a new initiative.</p>
            <button 
               onClick={() => setShowAddModal(true)}
               className="mt-6 text-blue-600 font-bold hover:underline flex items-center gap-2"
            >
               Create New Initiative <ArrowRight size={16} />
            </button>
        </div>
      )}

      {/* Modals */}
      {activeDetailProject && (
        <ProjectDetailModal 
          project={activeDetailProject} 
          tasks={tasks} 
          onClose={() => setSelectedProject(null)} 
        />
      )}

      {showAddModal && (
         <AddProjectModal onClose={() => setShowAddModal(false)} />
      )}
    </div>
  );
}
